declare_constante(__xac,''__xac''),
declare_constante(__xva,''__xva''),
declare_constante(__xst,''__xst''),
declare_constante(__xsi,''__xsi''),
importer(bibliotheque_spécifiée(__rev1),provenance(''./f0?n0=__rev1_.js'')),
#(
  =====================================================================================================================
  __m__worker11
),
definition_de_classe(
   nom_classe(__worker1),
   contenu(
      variable_privée(nom_de_la_variable,''''),
      variable_privée(url_du_site,''../''),
      variable_privée(la_chausette_web,null),
      variable_privée(adresse_du_websocket,''''),
      variable_privée(le_ws_est_actif,__xer),
      variable_privée(port_webso,''9998''),
      variable_privée(debut_timer0,appelf(element(performance),nomf(now),p())),
      variable_privée(debut_timer1,appelf(element(performance),nomf(now),p())),
      variable_publique(le_niveau_de_deverminage,0),
      #( objet des fonctions de traitement des revs ),
      variable_publique(__rev1,null),
      variable_privée(objet_envoye_au_serveur,null),
      variable_privée(utiliser_les_sockets,0),
      variable_publique(__deverminage,0),
      #(
        =========================================================================================================
      ),
      méthode(
         definition(nom(constructor),argument(nom_de_la_variable)),
         contenu(
            affecte(this.#nom_de_la_variable,nom_de_la_variable),
            affecte(
               this.__rev1,
               new(appelf(nomf(__rev1),p(null)))
            ),
            #(
              console.log( ''constructor de __worker'' );
            )
         )
      ),
      #(
        =========================================================================================================
      ),
      méthode(
         definition(nom(action_quand_message_recu_du_js_principal),asynchrone(),argument(le_message)),
         contenu(
            affecte(this.__deverminage,affecte(this.__deverminage,le_message.data.__xva.__parametres.__deverminage.valeur)),
            choix(
               si(
                  condition(egalstricte(this.__deverminage,2)),
                  alors(appelf(element(console),nomf(log),p(''le_message.data=''),p(le_message.data)))
               )
            ),
            declare_variable(obj,le_message.data),
            declare_variable(mat,null),
            declare_variable(mat_hash,[]),
            choix(
               si(
                  condition(
                     non(appelf(element(le_message.data),nomf(hasOwnProperty),p(''__xac'')))
                  ),
                  alors(
                     declare_variable(prop_trouvees,''''),
                     boucle_sur_objet_dans(
                        pourChaque(dans(declare_variable(i,null()),le_message.data)),
                        faire(affectop(''+='',prop_trouvees,concat(i,'','')))
                     ),
                     appelf(
                        nomf(postMessage),
                        p(
                           obj(("__xst",__xer),("__xme",concat(''<b>Le serveur ne peut être appelé.</b><br />Il manque la propriété "__xac"<br /> les propriétés trouvées sont '',prop_trouvees,'''')),("__xva",le_message.data))
                        )
                     ),
                     revenir()
                  )
               )
            ),
            declare_variable(obj1,appelf(element(this.__rev1),nomf(rev_tcm),p(le_message.data.__xac))),
            choix(
               si(condition(egalstricte(obj1.__xst,__xsu)),alors(affecte(mat,obj1.__xva))),
               sinon(
                  alors(
                     appelf(
                        nomf(postMessage),
                        p(obj(("__xst",__xer),("__xme",obj1.__xme),("__xva",le_message.data)))
                     ),
                     revenir()
                  )
               )
            ),
            affecte(tableau(nomt(obj),p(''mat'')),mat),
            #( console.log(''%cDANS __worker'',''color:red;background:yellow;'',''cmat='',mat,''obj.__xac='',obj.__xac); ),
            choix(
